        continue

    for uc_pub in uc_set:
        if uc_pub in citation:
            # Get assignee
            info = patent['Patents_info']
            assignee = 'Unknown'

            # Better pattern matching
            if 'by ' in info:
                match = re.search(r'by\s+([^,.]+)', info)
                if match:
                    assignee = match.group(1).strip()
            elif 'assigned to ' in info:
                match = re.search(r'assigned to\s+([^,.]+)', info)
                if match:
                    assignee = match.group(1).strip()
            else:
                # First word pattern - take until first verb
                match = re.search(r'^([^\s]+(?:\s+[^\s]+){0,3})', info)
                if match:
                    assignee = match.group(1).strip()

            if 'UNIV CALIFORNIA' not in assignee.upper():
                citing_data.append({
