            if len(code) >= 5 and '/' in code:
                subclass = code.split('/')[0]
                if len(subclass) >= 3:
                    cpc_codes.append(subclass)
    data['cpc_subclasses'] = list(set(cpc_codes))
    data['cited_uc'] = ''

print('\nCiting patents discovered:')
for i, data in enumerate(citing_data, 1):
